CREATE TABLE IF NOT EXISTS graduate_attributes (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), institution_id UUID NOT NULL REFERENCES institutions(id), name TEXT NOT NULL, description TEXT, sort_order INTEGER DEFAULT 0, created_at TIMESTAMPTZ DEFAULT now()); ALTER TABLE graduate_attributes ENABLE ROW LEVEL SECURITY; CREATE TABLE IF NOT EXISTS graduate_attribute_mappings (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), graduate_attribute_id UUID NOT NULL REFERENCES graduate_attributes(id) ON DELETE CASCADE, outcome_id UUID NOT NULL REFERENCES learning_outcomes(id) ON DELETE CASCADE, weight NUMERIC DEFAULT 1.0, created_at TIMESTAMPTZ DEFAULT now(), UNIQUE(graduate_attribute_id, outcome_id)); ALTER TABLE graduate_attribute_mappings ENABLE ROW LEVEL SECURITY; CREATE TABLE IF NOT EXISTS competency_frameworks (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), institution_id UUID NOT NULL REFERENCES institutions(id), name TEXT NOT NULL, description TEXT, version TEXT, is_active BOOLEAN DEFAULT true, created_at TIMESTAMPTZ DEFAULT now()); ALTER TABLE competency_frameworks ENABLE ROW LEVEL SECURITY; CREATE TABLE IF NOT EXISTS competency_items (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), framework_id UUID NOT NULL REFERENCES competency_frameworks(id) ON DELETE CASCADE, parent_id UUID REFERENCES competency_items(id), name TEXT NOT NULL, description TEXT, level INTEGER DEFAULT 0, sort_order INTEGER DEFAULT 0, created_at TIMESTAMPTZ DEFAULT now()); ALTER TABLE competency_items ENABLE ROW LEVEL SECURITY; CREATE TABLE IF NOT EXISTS competency_outcome_mappings (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), competency_item_id UUID NOT NULL REFERENCES competency_items(id) ON DELETE CASCADE, outcome_id UUID NOT NULL REFERENCES learning_outcomes(id) ON DELETE CASCADE, weight NUMERIC DEFAULT 1.0, created_at TIMESTAMPTZ DEFAULT now(), UNIQUE(competency_item_id, outcome_id)); ALTER TABLE competency_outcome_mappings ENABLE ROW LEVEL SECURITY; CREATE POLICY "ga_select" ON graduate_attributes FOR SELECT TO authenticated USING (true); CREATE POLICY "ga_admin" ON graduate_attributes FOR ALL TO authenticated USING (true); CREATE POLICY "ga_map_select" ON graduate_attribute_mappings FOR SELECT TO authenticated USING (true); CREATE POLICY "ga_map_admin" ON graduate_attribute_mappings FOR ALL TO authenticated USING (true); CREATE POLICY "cf_select" ON competency_frameworks FOR SELECT TO authenticated USING (true); CREATE POLICY "cf_admin" ON competency_frameworks FOR ALL TO authenticated USING (true); CREATE POLICY "ci_select" ON competency_items FOR SELECT TO authenticated USING (true); CREATE POLICY "ci_admin" ON competency_items FOR ALL TO authenticated USING (true); CREATE POLICY "com_select" ON competency_outcome_mappings FOR SELECT TO authenticated USING (true); CREATE POLICY "com_admin" ON competency_outcome_mappings FOR ALL TO authenticated USING (true);;
